 const [selectedDoor,setSelectedDoor]=useState<string|null>(null);
 const [fx,setFx]=useState<{id:number;kind:string;token?:string;from?:{x:number,y:number};to?:{x:number,y:number}}|null>(null);
 const [alert,setAlert]=useState(""); const [dying,setDying]=useState<Zombie[]>([]);
 const lastRevision=useRef(0),pendingWrites=useRef(0),lastSyncEvent=useRef(""),writeQueue=useRef<Promise<void>>(Promise.resolve());
