 const rawHero=game.heroes[game.active]||EMPTY_HERO,hero={...rawHero,used:rawHero.used||[]};
 const map=MISSIONS.find(v=>v.id===game.mission)||MISSIONS[0],{walls,buildings,doors,crates,exits,spawn}=map;
